23	/*
24	 * mutool grep -- command line tool for searching in documents
25	 */
26	
27	#include "mupdf/fitz.h"
28	
29	#ifdef _WIN32
30	#include <io.h>
31	#define isatty _isatty
32	#else
33	#include <unistd.h>
34	#endif
35	
36	static fz_context *ctx = NULL;
37	static fz_output *out = NULL;
38	static int show_page_number = 0;
39	static int show_file_name = 0;
40	static int search_backwards = 0;
41	
42	static const char *mark_open = "";
43	static const char *mark_close = "";
44	
45	static int mugrep_usage(void)
46	{
47		fprintf(stderr,
48			"usage: mugrep [options] pattern input.pdf [ input2.pdf ... ]\n"
49			"\t-p -\tpassword for encrypted PDF files\n"
50			"\t-F\tpattern is a fixed string\n"
51			"\t-a\tignore accents (diacritics)\n"
52			"\t-i\tignore case\n"
53			"\t-H\tprint filename for each match\n"
54			"\t-n\tprint page number for each match\n"
55			"advanced options:\n"
56			"\t-S\tcomma-separated list of search options\n"
57			"\t-O\tcomma-separated list of stext options\n"
58			"\t-b\tsearch pages in backwards order\n"
59			"\t-[ -\tstart marker\n"
60			"\t-] -\tend marker\n"
61			"\t-v\tverbose\n"
62			"\t-q\tquiet (don't print warnings and errors)\n"
63			"\n"
64		);
65		fputs(fz_search_options_usage, stderr);
66		fputs(fz_stext_options_usage, stderr);
67		return EXIT_FAILURE;
68	}
69	
70	static int
71	show_match_rec(fz_stext_block *block, fz_stext_line *begin_line, fz_stext_char *begin_ch, fz_stext_line *end_line, fz_stext_char *end_ch, int *last)
72	{
73		fz_stext_line *line;
74		fz_stext_char *ch;
75		while (block)
76		{
77			switch (block->type)
78			{
79			case FZ_STEXT_BLOCK_TEXT:
80				for (line = block->u.t.first_line; line; line = line->next)
81				{
82					if (line == begin_line)
83						begin_line = NULL;
84					if (!begin_line)
85					{
86						for (ch = line->first_char; ch; ch = ch->next)
87						{
88							if (ch == begin_ch)
89								fz_write_string(ctx, out, mark_open);
90							if (ch->c < 32)
91								fz_write_byte(ctx, out, ' ');
92							else if (ch->c != 0xad)
93								fz_write_rune(ctx, out, ch->c);
94							if (ch == end_ch)
95								fz_write_string(ctx, out, mark_close);
96							*last = ch->c;
97						}
98						if (!fz_is_unicode_whitespace(*last) && *last != 0xad)
99							fz_write_string(ctx, out, " ");
100					}
101					if (line == end_line)
102					{
103						return 1;
104					}
105				}
106				break;
107			case FZ_STEXT_BLOCK_STRUCT:
108				if (block->u.s.down)
109				{
110					if (show_match_rec(block->u.s.down->first_block, begin_line, begin_ch, end_line, end_ch, last))
111						return 1;
112				}
113				break;
114			}
115			block = block->next;
116		}
117		return 0;
118	}
119	
120	static void
121	show_match_snippet(char *file_name, int page_number, fz_stext_position begin, fz_stext_position end)
122	{
123		int last = 0;
124	
125		if (show_file_name)
126			fz_write_printf(ctx, out, "%s\t", file_name);
127		if (show_page_number)
128			fz_write_printf(ctx, out, "%d\t", page_number);
129	
130		if (begin.page == end.page)
131		{
132			(void)show_match_rec(begin.page->first_block, begin.line, begin.ch, end.line, end.ch, &last);
133		}
134		else
135		{
136			(void)show_match_rec(begin.page->first_block, begin.line, begin.ch, NULL, NULL, &last);
137			(void)show_match_rec(end.page->first_block, NULL, NULL, end.line, end.ch, &last);
138		}
139	
140		fz_write_byte(ctx, out, '\n');
141	}
142	
143	static int
144	mugrep_run(char *filename, fz_document *doc, char *pattern, fz_search_options options, fz_stext_options *stext_options, int verbose)
145	{
146		int page_count = fz_count_pages(ctx, doc);
147		fz_search *search = NULL;
148		fz_search_result res;
149		int found = 0;
150	
151		fz_var(search);
152	
153		fz_try(ctx)
154		{
155			search = fz_new_search(ctx, pattern, options);
156	
157			if (search_backwards)
158			{
159				fz_stext_page *page = fz_new_stext_page_from_page_number(ctx, doc, page_count - 1, stext_options);
160				fz_feed_search(ctx, search, page, page_count - 1);
161			}
162			else
163			{
164				fz_stext_page *page = fz_new_stext_page_from_page_number(ctx, doc, 0, stext_options);
165				fz_feed_search(ctx, search, page, 0);
166			}
167	
168			for (;;)
169			{
170				if (search_backwards)
171					res = fz_search_backwards(ctx, search);
172				else
173					res = fz_search_forwards(ctx, search);
174				if (res.reason == FZ_SEARCH_MATCH)
175				{
176					fz_search_match *details = res.u.match;
177	
178					found++;
179	
180					if (verbose)
181					{
182						printf("MATCH: %d quads (starting on page %d)\n", details->num_quads, details->quads[0].seq+1);
183					}
184	
185					show_match_snippet(filename, details->num_quads > 0 ? (details->quads[0].seq + 1) : 0, details->begin, details->end);
186				}
187				else if (res.reason == FZ_SEARCH_MORE_INPUT)
188				{
189					if (res.u.seq_needed < 0 || res.u.seq_needed >= page_count)
190					{
191						if (verbose)
192							printf("FEEDING END\n");
193						fz_feed_search(ctx, search, NULL, res.u.seq_needed);
194					}
195					else
196					{
197						int page_num = res.u.seq_needed;
198						if (verbose)
199							printf("FEEDING page %d\n", page_num);
200						fz_stext_page *page = fz_new_stext_page_from_page_number(ctx, doc, page_num, stext_options);
201						fz_feed_search(ctx, search, page, page_num);
202					}
203				}
204				else if (res.reason == FZ_SEARCH_COMPLETE)
205					break;
206			}
207		}
208		fz_always(ctx)
209			fz_drop_search(ctx, search);
210		fz_catch(ctx)
211			fz_rethrow(ctx);
212	
213		return found;
214	}
215	
216	static void silence(void *user, const char *message) {}
217	
218	int mugrep_main(int argc, char **argv)
219	{
220		fz_document *doc = NULL;
221		char *password = NULL; /* don't throw errors if encrypted */
222		char *filename;
223		char *pattern;
224		int result = EXIT_FAILURE;
225		int quiet = 0;
226		int c;
227		fz_search_options options = FZ_SEARCH_EXACT;
228		fz_stext_options stext_options = { 0 };
229		int verbose = 0;
230		int is_fixed_string = 0;
231	
232		ctx = fz_new_context(NULL, NULL, FZ_STORE_UNLIMITED);
233		if (!ctx)
234		{
235			fprintf(stderr, "cannot initialise context\n");
236			exit(1);
237		}
238	
239		fz_register_document_handlers(ctx);
240	
241		out = fz_stdout(ctx);
242	
243		if (isatty(1))
244		{
245			mark_open = "\x1b[1m";
246			mark_close = "\x1b[0m";
247		}
248	
249		fz_init_search_options(ctx, &options);
250	
251		while ((c = fz_getopt(argc, argv, "Faip:vO:S:nHb[:]:q")) != -1)
252		{
253			switch (c)
254			{
255			case 'O':
256				fz_parse_stext_options(ctx, &stext_options, fz_optarg);
257				break;
258			case 'S':
259				fz_parse_search_options(ctx, &options, fz_optarg);
260				break;
261			case 'F':
262				is_fixed_string = 1;
263				break;
264			case 'a':
265				options |= FZ_SEARCH_IGNORE_DIACRITICS;
266				break;
267			case 'i':
268				options |= FZ_SEARCH_IGNORE_CASE;
269				break;
270			case 'p':
271				password = fz_optarg;
272				break;
273			case 'n':
274				show_page_number = 1;
275				break;
276			case 'H':
277				show_file_name = 1;
278				break;
279			case 'b':
280				search_backwards = 1;
281				break;
282			case 'v':
283				verbose = 1;
284				break;
285			case 'q':
286				quiet = 1;
287				break;
288			case '[':
289				mark_open = mark_close = fz_optarg;
290				break;
291			case ']':
292				mark_close = fz_optarg;
293				break;
294			default:
295				return mugrep_usage();
296			}
297		}
298	
299		if (!is_fixed_string)
300			options |= FZ_SEARCH_REGEXP | FZ_SEARCH_KEEP_PARAGRAPHS;
301	
302		if (quiet > 0)
303		{
304			fz_set_warning_callback(ctx, silence, NULL);
305			fz_set_error_callback(ctx, silence, NULL);
306		}
307	
308		if (fz_optind == argc)
309			return mugrep_usage();
310	
311		pattern = argv[fz_optind++];
312	
313		fz_var(doc);
314	
315		fz_try(ctx)
316		{
317			while (fz_optind < argc)
318			{
319				filename = argv[fz_optind++];
320	
321				doc = fz_open_document(ctx, filename);
322				if (fz_needs_password(ctx, doc))
323					if (!fz_authenticate_password(ctx, doc, password))
324					{
325						fz_warn(ctx, "cannot authenticate password: %s", filename);
326						fz_drop_document(ctx, doc);
327						doc = NULL;
328						continue;
329					}
330	
331				if (mugrep_run(filename, doc, pattern, options, &stext_options, verbose))
332					result = EXIT_SUCCESS;
333	
334				fz_drop_document(ctx, doc);
335				doc = NULL;
336			}
337		}
338		fz_always(ctx)
339		{
340			fz_drop_document(ctx, doc);
341		}
342		fz_catch(ctx)
343		{
344			fz_report_error(ctx);
345			result = EXIT_FAILURE;
346		}
347	
348		fz_drop_context(ctx);
349	
350		return result;
351	}
