45	void fz_init_search_options(fz_context *ctx, fz_search_options *opts)
46	{
47		*opts = 0;
48	}
49	
50	fz_search_options *fz_parse_search_options(fz_context *ctx, fz_search_options *opts, const char *args)
51	{
52		fz_options *options = fz_new_options(ctx, args);
53		fz_try(ctx)
54		{
55			fz_init_search_options(ctx, opts);
56			fz_apply_search_options(ctx, opts, options);
57			fz_throw_on_unused_options(ctx, options, "search");
58		}
59		fz_always(ctx)
60			fz_drop_options(ctx, options);
61		fz_catch(ctx)
62			fz_rethrow(ctx);
63	
64		return opts;
65	}
66	
67	void fz_apply_search_options(fz_context *ctx, fz_search_options *opts, fz_options *args)
68	{
69		fz_search_options mask = *opts;
70	
71		// TODO: stricter parsing of options bitmask string
72		if (fz_lookup_option_yes(ctx, args, "exact")) mask |= FZ_SEARCH_EXACT;
73		if (fz_lookup_option_yes(ctx, args, "ignore-case")) mask |= FZ_SEARCH_IGNORE_CASE;
74		if (fz_lookup_option_yes(ctx, args, "ignore-diacritics")) mask |= FZ_SEARCH_IGNORE_DIACRITICS;
75		if (fz_lookup_option_yes(ctx, args, "regexp")) mask |= FZ_SEARCH_REGEXP;
76		if (fz_lookup_option_yes(ctx, args, "keep-lines")) mask |= FZ_SEARCH_KEEP_LINES;
77		if (fz_lookup_option_yes(ctx, args, "keep-paragraphs")) mask |= FZ_SEARCH_KEEP_PARAGRAPHS;
78		if (fz_lookup_option_yes(ctx, args, "keep-hyphens")) mask |= FZ_SEARCH_KEEP_HYPHENS;
79	
80		fz_validate_options(ctx, args, "search");
81	
82		*opts = mask;
83	}
84	
85	/* Enumerate marked selection */
86	
87	static float hdist(fz_point *dir, fz_point *a, fz_point *b)
88	{
89		float dx = b->x - a->x;
90		float dy = b->y - a->y;
91		return fz_abs(dx * dir->x - dy * dir->y);
92	}
93	
94	static float vdist(fz_point *dir, fz_point *a, fz_point *b)
95	{
96		float dx = b->x - a->x;
97		float dy = b->y - a->y;
98		return fz_abs(dx * dir->y - dy * dir->x);
99	}
100	
101	static float vecdot(fz_point a, fz_point b)
102	{
103		return a.x * b.x + a.y * b.y;
104	}
105	
106	static float linedist(fz_point origin, fz_point dir, fz_point q)
107	{
108		return vecdot(dir, fz_make_point(q.x - origin.x, q.y - origin.y));
109	}
110	
111	static int line_length(fz_stext_line *line)
112	{
113		fz_stext_char *ch;
114		int n = 0;
115		for (ch = line->first_char; ch; ch = ch->next)
116			++n;
117		return n;
118	}
119	
120	static float largest_size_in_line(fz_stext_line *line)
121	{
122		fz_stext_char *ch;
123		float size = 0;
124		for (ch = line->first_char; ch; ch = ch->next)
125			if (ch->size > size)
126				size = ch->size;
127		return size;
128	}
129	
130	static int find_closest_in_line(fz_stext_line *line, int idx, fz_point q)
131	{
132		fz_stext_char *ch;
133		float closest_dist = 1e30f;
134		int closest_idx = idx;
135		float d1, d2;
136	
137		float hsize = largest_size_in_line(line) / 2;
138		fz_point vdir = fz_make_point(-line->dir.y, line->dir.x);
139		fz_point hdir = line->dir;
140	
141		// Compute mid-line from quads!
142		fz_point p1 = fz_make_point(
143			(line->first_char->quad.ll.x + line->first_char->quad.ul.x) / 2,
144			(line->first_char->quad.ll.y + line->first_char->quad.ul.y) / 2
145		);
146	
147		// Signed distance perpendicular mid-line (positive is below)
148		float vdist = linedist(p1, vdir, q);
149		if (vdist < -hsize)
150			return idx;
151		if (vdist > hsize)
152			return idx + line_length(line);
153	
154		for (ch = line->first_char; ch; ch = ch->next)
155		{
156			if (ch->bidi & 1)
157			{
158				d1 = fz_abs(linedist(ch->quad.lr, hdir, q));
159				d2 = fz_abs(linedist(ch->quad.ll, hdir, q));
160			}
161			else
162			{
163				d1 = fz_abs(linedist(ch->quad.ll, hdir, q));
164				d2 = fz_abs(linedist(ch->quad.lr, hdir, q));
165			}
166	
167			if (d1 < closest_dist)
168			{
169				closest_dist = d1;
170				closest_idx = idx;
171			}
172	
173			if (d2 < closest_dist)
174			{
175				closest_dist = d2;
176				closest_idx = idx + 1;
177			}
178	
179			++idx;
180		}
181	
182		return closest_idx;
183	}
184	
185	static int find_closest_in_page(fz_stext_page *page, fz_point q)
186	{
187		fz_stext_block *block;
188		fz_stext_line *line;
189		fz_stext_line *closest_line = NULL;
190		int closest_idx = 0;
191		float closest_vdist = 1e30f;
192		float closest_hdist = 1e30f;
193		int idx = 0;
194	
195		for (block = page->first_block; block; block = block->next)
196		{
197			if (block->type != FZ_STEXT_BLOCK_TEXT)
198				continue;
199			for (line = block->u.t.first_line; line; line = line->next)
200			{
201				float hsize = largest_size_in_line(line) / 2;
202				fz_point hdir = line->dir;
203				fz_point vdir = fz_make_point(-line->dir.y, line->dir.x);
204	
205				// Compute mid-line from quads!
206				fz_point p1 = fz_make_point(
207					(line->first_char->quad.ll.x + line->first_char->quad.ul.x) / 2,
208					(line->first_char->quad.ll.y + line->first_char->quad.ul.y) / 2
209				);
210				fz_point p2 = fz_make_point(
211					(line->last_char->quad.lr.x + line->last_char->quad.ur.x) / 2,
212					(line->last_char->quad.lr.y + line->last_char->quad.ur.y) / 2
213				);
214	
215				// Signed distance perpendicular mid-line (positive is below)
216				float vdist = linedist(p1, vdir, q);
217	
218				// Signed distance tangent to mid-line from end points (positive is to end)
219				float hdist1 = linedist(p1, hdir, q);
220				float hdist2 = linedist(p2, hdir, q);
221	
222				// Within the line itself!
223				if (vdist >= -hsize && vdist <= hsize && (hdist1 > 0) != (hdist2 > 0))
224				{
225					closest_vdist = 0;
226					closest_hdist = 0;
227					closest_line = line;
228					closest_idx = idx;
229				}
230				else
231				{
232					// Vertical distance from mid-line.
233					float avdist = fz_abs(vdist);
234	
235					// Horizontal distance from closest end-point
236					float ahdist = fz_min(fz_abs(hdist1), fz_abs(hdist2));
237	
238					if (avdist < hsize)
239					{
240						// Within extended line
241						if (ahdist <= closest_hdist)
242						{
243							closest_vdist = 0;
244							closest_hdist = ahdist;
245							closest_line = line;
246							closest_idx = idx;
247						}
248					}
249					else
250					{
251						// Outside line
252						// TODO: closest column?
253						if (avdist <= closest_vdist)
254						{
255							closest_vdist = avdist;
256							closest_line = line;
257							closest_idx = idx;
258						}
259					}
260				}
261	
262				idx += line_length(line);
263			}
264		}
265	
266		if (closest_line)
267			return find_closest_in_line(closest_line, closest_idx, q);
268	
269		return 0;
270	}
271	
272	struct callbacks
273	{
274		void (*on_char)(fz_context *ctx, void *arg, fz_stext_line *ln, fz_stext_char *ch);
275		void (*on_line)(fz_context *ctx, void *arg, fz_stext_line *ln);
276		void *arg;
277	};
278	
279	static void
280	fz_enumerate_selection(fz_context *ctx, fz_stext_page *page, fz_point a, fz_point b, struct callbacks *cb)
281	{
282		fz_stext_block *block;
283		fz_stext_line *line;
284		fz_stext_char *ch;
285		int idx, start, end;
286		int inside;
287	
288		start = find_closest_in_page(page, a);
289		end = find_closest_in_page(page, b);
290	
291		if (start > end)
292			idx = start, start = end, end = idx;
293	
294		if (start == end)
295			return;
296	
297		inside = 0;
298		idx = 0;
299		for (block = page->first_block; block; block = block->next)
300		{
301			if (block->type != FZ_STEXT_BLOCK_TEXT)
302				continue;
303			for (line = block->u.t.first_line; line; line = line->next)
304			{
305				for (ch = line->first_char; ch; ch = ch->next)
306				{
307					if (!inside)
308						if (idx == start)
309							inside = 1;
310					if (inside)
311						cb->on_char(ctx, cb->arg, line, ch);
312					if (++idx == end)
313						return;
314				}
315				if (inside)
316					cb->on_line(ctx, cb->arg, line);
317			}
318		}
319	}
320	
321	fz_quad
322	fz_snap_selection(fz_context *ctx, fz_stext_page *page, fz_point *a, fz_point *b, int mode)
323	{
324		fz_stext_block *block;
325		fz_stext_line *line;
326		fz_stext_char *ch;
327		fz_quad handles;
328		int idx, start, end;
329		int pc;
330	
331		start = find_closest_in_page(page, *a);
332		end = find_closest_in_page(page, *b);
333	
334		if (start > end)
335			idx = start, start = end, end = idx;
336	
337		handles.ll = handles.ul = *a;
338		handles.lr = handles.ur = *b;
339	
340		idx = 0;
341		for (block = page->first_block; block; block = block->next)
342		{
343			if (block->type != FZ_STEXT_BLOCK_TEXT)
344				continue;
345			for (line = block->u.t.first_line; line; line = line->next)
346			{
347				pc = '\n';
348				for (ch = line->first_char; ch; ch = ch->next)
349				{
350					if (idx <= start)
351					{
352						if (mode == FZ_SELECT_CHARS
353							|| (mode == FZ_SELECT_WORDS && (pc == ' ' || pc == '\n'))
354							|| (mode == FZ_SELECT_LINES && (pc == '\n')))
355						{
356							handles.ll = ch->quad.ll;
357							handles.ul = ch->quad.ul;
358							*a = ch->origin;
359						}
360					}
361					if (idx >= end)
362					{
363						if (mode == FZ_SELECT_CHARS
364							|| (mode == FZ_SELECT_WORDS && (ch->c == ' ')))
365						{
366							handles.lr = ch->quad.ll;
367							handles.ur = ch->quad.ul;
368							*b = ch->origin;
369							return handles;
370						}
371						if (!ch->next)
372						{
373							handles.lr = ch->quad.lr;
374							handles.ur = ch->quad.ur;
375							*b = ch->quad.lr;
376							return handles;
377						}
378					}
379					pc = ch->c;
380					++idx;
381				}
382			}
383		}
384	
385		return handles;
386	}
387	
388	/* Highlight selection */
389	
390	struct highlight
391	{
392		int len, cap;
393		fz_quad *box;
394		float hfuzz, vfuzz;
395	};
396	
397	static int same_point(fz_point a, fz_point b)
398	{
399		int dx = fz_abs(a.x - b.x);
400		int dy = fz_abs(a.y - b.y);
401		return (dx < 0.1 && dy < 0.1);
402	}
403	
404	static int is_near(float hfuzz, float vfuzz, fz_point hdir, fz_point end, fz_point p1, fz_point p2)
405	{
406		float v = fz_abs(linedist(end, fz_make_point(-hdir.y, hdir.x), p1));
407		float d1 = fz_abs(linedist(end, hdir, p1));
408		float d2 = fz_abs(linedist(end, hdir, p2));
409		return (v < vfuzz && d1 < hfuzz && d1 < d2);
410	}
411	
412	static void on_highlight_char(fz_context *ctx, void *arg, fz_stext_line *line, fz_stext_char *ch)
413	{
414		struct highlight *hits = arg;
415		float vfuzz = hits->vfuzz * ch->size;
416		float hfuzz = hits->hfuzz * ch->size;
417		fz_point dir = line->dir;
418	
419		// Skip zero-extent quads
420		if (same_point(ch->quad.ll, ch->quad.lr))
421			return;
422	
423		if (hits->len > 0)
424		{
425			fz_quad *end = &hits->box[hits->len-1];
426	
427			if (is_near(hfuzz, vfuzz, dir, end->lr, ch->quad.ll, ch->quad.lr) &&
428				is_near(hfuzz, vfuzz, dir, end->ur, ch->quad.ul, ch->quad.ur))
429			{
430				end->ur = ch->quad.ur;
431				end->lr = ch->quad.lr;
432				return;
433			}
434	
435			if (is_near(hfuzz, vfuzz, dir, end->ll, ch->quad.lr, ch->quad.ll) &&
436				is_near(hfuzz, vfuzz, dir, end->ul, ch->quad.ur, ch->quad.ul))
437			{
438				end->ul = ch->quad.ul;
439				end->ll = ch->quad.ll;
440				return;
441			}
442		}
443	
444		if (hits->len < hits->cap)
445			hits->box[hits->len++] = ch->quad;
446	}
447	
448	static void on_highlight_line(fz_context *ctx, void *arg, fz_stext_line *line)
449	{
450	}
451	
452	int
453	fz_highlight_selection(fz_context *ctx, fz_stext_page *page, fz_point a, fz_point b, fz_quad *quads, int max_quads)
454	{
455		struct callbacks cb;
456		struct highlight hits;
457	
458		hits.len = 0;
459		hits.cap = max_quads;
460		hits.box = quads;
461		hits.hfuzz = 0.5f; /* merge large gaps */
462		hits.vfuzz = 0.1f;
463	
464		cb.on_char = on_highlight_char;
465		cb.on_line = on_highlight_line;
466		cb.arg = &hits;
467	
468		fz_enumerate_selection(ctx, page, a, b, &cb);
469	
470		return hits.len;
471	}
472	
473	/* Copy selection */
474	
475	static void on_copy_char(fz_context *ctx, void *arg, fz_stext_line *line, fz_stext_char *ch)
476	{
477		fz_buffer *buffer = arg;
478		int c = ch->c;
479		if (c < 32)
480			c = FZ_REPLACEMENT_CHARACTER;
481		fz_append_rune(ctx, buffer, c);
482	}
483	
484	static void on_copy_line_crlf(fz_context *ctx, void *arg, fz_stext_line *line)
485	{
486		fz_buffer *buffer = arg;
487		fz_append_byte(ctx, buffer, '\r');
488		fz_append_byte(ctx, buffer, '\n');
489	}
490	
491	static void on_copy_line_lf(fz_context *ctx, void *arg, fz_stext_line *line)
492	{
493		fz_buffer *buffer = arg;
494		fz_append_byte(ctx, buffer, '\n');
495	}
496	
497	char *
498	fz_copy_selection(fz_context *ctx, fz_stext_page *page, fz_point a, fz_point b, int crlf)
499	{
500		struct callbacks cb;
501		fz_buffer *buffer;
502		unsigned char *s;
503	
504		buffer = fz_new_buffer(ctx, 1024);
505		fz_try(ctx)
506		{
507			cb.on_char = on_copy_char;
508			cb.on_line = crlf ? on_copy_line_crlf : on_copy_line_lf;
509			cb.arg = buffer;
510	
511			fz_enumerate_selection(ctx, page, a, b, &cb);
512			fz_terminate_buffer(ctx, buffer);
513		}
514		fz_catch(ctx)
515		{
516			fz_drop_buffer(ctx, buffer);
517			fz_rethrow(ctx);
518		}
519		fz_buffer_extract(ctx, buffer, &s); /* take over the data */
520		fz_drop_buffer(ctx, buffer);
521		return (char*)s;
522	}
523	
524	char *
525	fz_copy_rectangle(fz_context *ctx, fz_stext_page *page, fz_rect area, int crlf)
526	{
527		fz_stext_block *block;
528		fz_stext_line *line;
529		fz_stext_char *ch;
530		fz_buffer *buffer;
531		unsigned char *s;
532	
533		int need_new_line = 0;
534	
535		buffer = fz_new_buffer(ctx, 1024);
536		fz_try(ctx)
537		{
538			for (block = page->first_block; block; block = block->next)
539			{
540				if (block->type != FZ_STEXT_BLOCK_TEXT)
541					continue;
542				for (line = block->u.t.first_line; line; line = line->next)
543				{
544					int line_had_text = 0;
545					for (ch = line->first_char; ch; ch = ch->next)
546					{
547						fz_rect r = fz_rect_from_quad(ch->quad);
548						if (!fz_is_empty_rect(fz_intersect_rect(r, area)))
549						{
550							line_had_text = 1;
551							if (need_new_line)
552							{
553								fz_append_string(ctx, buffer, crlf ? "\r\n" : "\n");
554								need_new_line = 0;
555							}
556							fz_append_rune(ctx, buffer, ch->c < 32 ? FZ_REPLACEMENT_CHARACTER : ch->c);
557						}
558					}
559					if (line_had_text)
560						need_new_line = 1;
561				}
562			}
563			fz_terminate_buffer(ctx, buffer);
564		}
565		fz_catch(ctx)
566		{
567			fz_drop_buffer(ctx, buffer);
568			fz_rethrow(ctx);
569		}
570	
571		fz_buffer_extract(ctx, buffer, &s); /* take over the data */
572		fz_drop_buffer(ctx, buffer);
573		return (char*)s;
574	}
575	
576	static int my_isspace(int ch)
577	{
578		/* \t, \n, \v, \f, \r, space */
579		return (ch == 9 || ch == 10 || ch == 11 || ch == 12 || ch == 13 || ch == 32);
580	}
581	
582	int fz_is_unicode_whitespace(int c)
583	{
584		if (fz_is_unicode_space_equivalent(c))
585			return 1;
586		if (c == 0x2028)
587			return 1; /* Line separator */
588		if (c == 0x2029)
589			return 1; /* Paragraph separator */
590		if (c > 0 && c < 256 && my_isspace(c))
591			return 1;
592		return 0;
593	}
