595	/*
596	 * NEW ADVANCED SEARCH API
597	 */
598	
599	int
600	fz_is_unicode_space_equivalent(int c)
601	{
602		switch (c)
603		{
604		case 0xa0:	/* NO-BREAK-SPACE */
605		case 0x1680:	/* OGHAM SPACE MARK */
606		case 0x2000:	/* EN QUAD */
607		case 0x2001:	/* EM QUAD */
608		case 0x2002:	/* EN SPACE */
609		case 0x2003:	/* EM SPACE */
610		case 0x2004:	/* THREE-PER-EM-SPACE */
611		case 0x2005:	/* FOUR-PER-EM-SPACE */
612		case 0x2006:	/* SIX-PER-EM-SPACE */
613		case 0x2007:	/* FIGURE-SPACE */
614		case 0x2008:	/* PUNCTUATION-SPACE */
615		case 0x2009:	/* THIN-SPACE */
616		case 0x200A:	/* HAIR-SPACE */
617		case 0x202F:	/* NARROW-NO-BREAK-SPACE */
618		case 0x205F:	/* MEDIUM-MATHEMATICAL-SPACE */
619		case 0x3000:	/* IDEOGRAPHIC-SPACE */
620			return 1;
621		}
622	
623		return 0;
624	}
625	
626	static const char *advance_one_utf8(const char *s, const char *p)
627	{
628		if (p >= s && *p == 0x00)
629			return NULL;
630		p++;
631		while (((*p & 0x80) != 0) && ((*p & 0xc0) != 0xc0) && *p)
632			p++;
633		return p;
634	}
635	
636	static const char *retreat_one_utf8(const char *s, const char *p)
637	{
638		if (p <= s)
639			return NULL;
640		do
641			--p;
642		while (((*p & 0x80) != 0) && ((*p & 0xc0) != 0xc0) && p > s);
643		return p;
644	}
645	
646	static inline int canon(int c)
647	{
648		if (c == '\r' || c == '\n' || c == '\t' || fz_is_unicode_space_equivalent(c))
649			return ' ';
650		return c;
651	}
652	
653	static inline int is_marking_nonspacing(const char *h)
654	{
655		/* match must not end between base and combining character */
656		int hc;
657		if (*h < 0)
658		{
659			(void)fz_chartorune(&hc, h);
660			if (ucdn_get_general_category(hc) == UCDN_GENERAL_CATEGORY_MN)
661				return 1;
662		}
663		return 0;
664	}
665	
666	static const char *match_exact(const char *h, const char *n)
667	{
668		int hc, nc;
669		do {
670			n += fz_chartorune(&nc, n);
671			if (nc == 0)
672			{
673				if (is_marking_nonspacing(h))
674					return NULL;
675				return h;
676			}
677			h += fz_chartorune(&hc, h);
678		} while (hc == nc);
679		return NULL;
680	}
681	
682	static const char *find_exact(fz_context *ctx, void *dummy, const char *s, const char *p, const char *needle, const char **endp)
683	{
684		const char *end;
685		while (p)
686		{
687			end = match_exact(p, needle);
688			if (end)
689				return *endp = end, p;
690			p = advance_one_utf8(s, p);
691		}
692		return *endp = NULL, NULL;
693	}
694	
695	static const char *find_rev_exact(fz_context *ctx, void *dummy, const char *s, const char *p, const char *needle, const char **endp)
696	{
697		const char *end;
698		p = retreat_one_utf8(s, p);
699		while (p)
700		{
701			end = match_exact(p, needle);
702			if (end)
703				return *endp = end, p;
704	
705			p = retreat_one_utf8(s, p);
706		}
707		return *endp = NULL, NULL;
708	}
709	
710	static const char *find_regexp(fz_context *ctx, void *arg, const char *s, const char *p, const char *needle, const char **endp)
711	{
712		Reprog **prog = (Reprog **)arg;
713		Resub m;
714	
715		while (p)
716		{
717			int bol = (p == s) || (p[-1] == '\n');
718			int result = js_regexec(*prog, p, &m, bol ? 0 : REG_NOTBOL);
719			if (result < 0)
720				fz_throw(ctx, FZ_ERROR_ARGUMENT, "regexec failure");
721			if (result == 1)
722				return *endp = NULL, NULL;
723			if (m.sub[0].ep - m.sub[0].sp > 0 && !is_marking_nonspacing(m.sub[0].ep))
724				return *endp = m.sub[0].ep, m.sub[0].sp;
725			p = advance_one_utf8(s, p);
726		}
727	
728		return *endp = NULL, NULL;
729	}
730	
731	static const char *find_rev_regexp(fz_context *ctx, void *arg, const char *s, const char *p, const char *needle, const char **endp)
732	{
733		/* This is pretty horrible.
734		 * We search from the start for a match; if we fail to find it, no match.
735		 * If we match, but the match starts after our offset, no match.
736		 * Otherwise, we keep looking for matches further on in the buffer.
737		 */
738		const char *start, *later_end, *later_start;
739	
740		start = find_regexp(ctx, arg, s, s, needle, endp);
741		if (start == NULL || (start - s) >= (p - s))
742		{
743			/* No match at all. */
744			*endp = NULL;
745			return NULL;
746		}
747	
748		/* Now look for a later one */
749		while (1)
750		{
751			later_start = find_regexp(ctx, arg, s, *endp, needle, &later_end);
752			if (later_start == NULL || (later_end - s) > (p - s))
753				return start;
754			start = later_start;
755			*endp = later_end;
756		}
757	}
