759	/**
760	  A set of functions to implement a 'finder' for the match
761	  functions.
762	 */
763	typedef struct
764	{
765		/* init: May be NULL. If not, it will be called with the needle
766		 * that is to be used. This allows the needle to be 'compiled'.
767		 * This should throw if the needle fails to compile.
768		 */
769		void (*init)(fz_context *ctx, void *find_arg, const char *needle);
770	
771		/* find: Search for the needle in the haystack.
772		 *
773		 * Return value is NULL (and *endp = NULL) if no match found.
774		 * Otherwise, return value is the start of the match to the
775		 * needle in the haystack (and *endp = one byte beyond
776		 * the last character included in the match).
777		 */
778		const char *(*find)(fz_context *ctx, void *find_arg, const char *haystack, const char *current, const char *needle, const char **endp);
779	
780		/* find_rev: Search for the needle backwards in the haystack.
781		 *
782		 * Return value is NULL (and *endp = NULL) if no match found.
783		 * Otherwise, return value is the start of the match to the
784		 * needle in the haystack (and *endp = one byte beyond
785		 * the last character included in the match).
786		 */
787		const char *(*find_rev)(fz_context *ctx, void *find_arg, const char *haystack, const char *current, const char *needle, const char **endp);
788	
789		/* fin: Maybe NULL. If not, it will be called whenever the
790		 * search process has finished (after a successful init).
791		 * This allows the 'compiled' needle to be freed. Must
792		 * never throw.
793		 */
794		void (*fin)(fz_context *ctx, void *find_arg);
795	} fz_match_finder;
796	
797	static const fz_match_finder simple_finder =
798	{
799		NULL,
800		find_exact,
801		find_rev_exact,
802		NULL
803	};
