848	/**
849	  Bitfield of transforms to apply to search text before passing to
850	  the finder functions.
851	
852	  All search text is transformed so that newline, carriage return,
853	  tab, line separator, paragraph separator and non-breaking space
854	  are are converted to space.
855	
856	  Runs of multiple "spaces" (including the above chars) are
857	  transformed to single spaces.
858	
859	  Logical OR these together as appropriate to make the required
860	  transformations.
861	
862	  In general these will be applied from larger numbers to smaller
863	  numbers.
864	 */
865	typedef enum
866	{
867		FZ_TEXT_TRANSFORM_NONE = 0,
868	
869		/* Perform unicode composition on the strings. */
870		FZ_TEXT_TRANSFORM_COMPOSE = 1,
871	
872		/* Convert all characters to upper case. */
873		FZ_TEXT_TRANSFORM_UPPERCASE = 2,
874	
875		/* Convert full width ASCII variants to standard ASCII variants */
876		FZ_TEXT_TRANSFORM_FULLWIDTH_ASCII = 4,
877	
878		/* Strip "marking, non-spacing" characters out of the string. */
879		FZ_TEXT_TRANSFORM_STRIP_MARKING_NONSPACING = 8,
880	
881		/* Perform unicode decomposition on the string. (i.e. NFD,
882		 * according to Unicode tr15)
883		 */
884		FZ_TEXT_TRANSFORM_DECOMPOSE = 16,
885	
886		/* Perform unicode compatibility decomposition on the string.
887		 * (i.e. NFKD according to Unicode tr15)
888		 */
889		FZ_TEXT_TRANSFORM_COMPATIBILITY_DECOMPOSE = 32,
890	
891		/* Normalize all hyphen-equivalents (fz_is_unicode_hyphen) to '-'.
892		 */
893		FZ_TEXT_TRANSFORM_NORMALIZE_HYPHENS = 64,
894	
895		/* Preserve line breaks (mainly for use with regexps) -
896		 * line breaks are preserved as single \n.
897		 */
898		FZ_TEXT_TRANSFORM_KEEP_LINES = 256,
899	
900		/* Preserve paragraph breaks (mainly for use with regexps) -
901		 * paragraph breaks are preserved as double \n.
902		 */
903		FZ_TEXT_TRANSFORM_KEEP_PARAGRAPHS = 512,
904	
905		/* Preserve hyphens. Without this, they are removed and
906		 * lines joined.
907		 */
908		FZ_TEXT_TRANSFORM_KEEP_HYPHENS = 1024,
909	
910	
911		/* And some useful combinations of these flags */
912	
913		/* NORMAL: case sensitive text matching, allowing for different
914		 * encodings of the same diacritics.
915		 */
916		FZ_TEXT_TRANSFORM__NORMAL =
917			FZ_TEXT_TRANSFORM_COMPATIBILITY_DECOMPOSE |
918			FZ_TEXT_TRANSFORM_NORMALIZE_HYPHENS |
919			FZ_TEXT_TRANSFORM_FULLWIDTH_ASCII |
920			FZ_TEXT_TRANSFORM_COMPOSE,
921	
922		/* IGNORE_CASE: flags necessary for case insensitive matching */
923		FZ_TEXT_TRANSFORM__IGNORE_CASE =
924			FZ_TEXT_TRANSFORM_COMPATIBILITY_DECOMPOSE |
925			FZ_TEXT_TRANSFORM_NORMALIZE_HYPHENS |
926			FZ_TEXT_TRANSFORM_FULLWIDTH_ASCII |
927			FZ_TEXT_TRANSFORM_UPPERCASE |
928			FZ_TEXT_TRANSFORM_COMPOSE,
929	
930		/* IGNORE_DIACRITICS: flags necessary to ignore marking non-spacing characters (i.e. diacritics) */
931		FZ_TEXT_TRANSFORM__IGNORE_DIACRITICS =
932			FZ_TEXT_TRANSFORM_COMPATIBILITY_DECOMPOSE |
933			FZ_TEXT_TRANSFORM_NORMALIZE_HYPHENS |
934			FZ_TEXT_TRANSFORM_FULLWIDTH_ASCII |
935			FZ_TEXT_TRANSFORM_STRIP_MARKING_NONSPACING |
936			FZ_TEXT_TRANSFORM_COMPOSE,
937	
938		/* IGNORE_CASE_DIACRITICS: flags necessary to ignore both case and marking non-spacing characters (i.e. diacritics) */
939		FZ_TEXT_TRANSFORM__IGNORE_CASE_DIACRITICS =
940			FZ_TEXT_TRANSFORM_COMPATIBILITY_DECOMPOSE |
941			FZ_TEXT_TRANSFORM_NORMALIZE_HYPHENS |
942			FZ_TEXT_TRANSFORM_FULLWIDTH_ASCII |
943			FZ_TEXT_TRANSFORM_STRIP_MARKING_NONSPACING |
944			FZ_TEXT_TRANSFORM_UPPERCASE |
945			FZ_TEXT_TRANSFORM_COMPOSE,
946	} fz_text_transform;
947	
948	/* Given that the maximum we can decompose from a single char is
949	 * 18, it seems reasonable to only be able compose the same number?
950	 * Anyway, 32 should be WAY more than is ever needed in the real
951	 * world.
952	 */
953	typedef struct
954	{
955		int len;
956		int cache[32];
957		size_t pos[32];
958	} transform_cache;
959	
960	static size_t
961	flush_transform_cache(fz_context *ctx, char *output, size_t *index, fz_text_transform transform, transform_cache *cache)
962	{
963		int i, j, k, n = cache->len;
964		char dummy[4];
965		size_t len;
966	
967		if (n == 0)
968			return 0;
969	
970		/* First off, do we need to bubblesort?*/
971		if (transform & (FZ_TEXT_TRANSFORM_COMPATIBILITY_DECOMPOSE | FZ_TEXT_TRANSFORM_COMPATIBILITY_DECOMPOSE | FZ_TEXT_TRANSFORM_COMPOSE))
972		{
973			/* We need to reorder. Simple bubblesort. */
974			for (i = 0; i < n-1; i++)
975			{
976				int i_ccc = ucdn_get_combining_class(cache->cache[i]);
977				for (j = i+1; j < n; j++)
978				{
979					int j_ccc = ucdn_get_combining_class(cache->cache[j]);
980					if (i_ccc > j_ccc)
981					{
982						int t = cache->cache[j];
983						cache->cache[j] = cache->cache[i];
984						cache->cache[i] = t;
985	
986						// NOTE: We do NOT swap the positions here.
987						// The index must be in increasing order for lookup_stext_position to work, so we have no choice here.
988						// This means the index will be jumbled for the individual marks in combining characters.
989						// That shouldn't matter because we should not split text in the middle of a character and its combining marks.
990	
991						i_ccc = j_ccc;
992					}
993				}
994			}
995		}
996	
997		if (transform & FZ_TEXT_TRANSFORM_COMPOSE)
998		{
999			for (i = 0, j = 1; j < n; j++)
1000			{
1001				uint32_t a;
1002				if (ucdn_compose(&a, cache->cache[i], cache->cache[j]))
1003				{
1004					/* We composed. */
1005					cache->cache[i] = (int)a;
1006				}
1007				else
1008				{
1009					/* Composition failed. */
1010					cache->cache[++i] = cache->cache[j];
1011					cache->pos[i] = cache->pos[j];
1012				}
1013			}
1014			n = i+1;
1015		}
1016	
1017		/* Now actually do the output */
1018		len = 0;
1019		for (i = 0; i < n; i++)
1020		{
1021			if (output)
1022			{
1023				j = fz_runetochar(output, cache->cache[i]);
1024				output += j;
1025			}
1026			else
1027			{
1028				j = fz_runetochar(dummy, cache->cache[i]);
1029			}
1030			if (index)
1031			{
1032				for (k = 0; k < j; k++, index++)
1033					*index = cache->pos[i];
1034			}
1035			len += j;
1036		}
1037		return len;
1038	}
1039	
1040	static size_t
1041	transform_char(fz_context *ctx, char *output, size_t *index, int c, size_t pos, fz_text_transform transform, transform_cache *cache)
1042	{
1043		size_t len;
1044		int ccc;
1045	
1046		if (transform & FZ_TEXT_TRANSFORM_DECOMPOSE)
1047		{
1048			uint32_t a, b;
1049			if (ucdn_decompose((uint32_t)c, &a, &b))
1050			{
1051				size_t len2 = transform_char(ctx, output, index, a, pos, transform, cache);
1052				if (index)
1053					index += len2;
1054				if (output)
1055					output += len2;
1056				len = transform_char(ctx, output, index, b, pos, transform, cache);
1057				if (index)
1058					index += len;
1059				if (output)
1060					output += len;
1061				return len2 + len;
1062			}
1063			transform &= ~FZ_TEXT_TRANSFORM_DECOMPOSE;
1064			/* Otherwise, it doesn't decompose to anything, so just fall
1065			 * through and process it as is.
1066			 */
1067		}
1068	
1069		if (transform & FZ_TEXT_TRANSFORM_COMPATIBILITY_DECOMPOSE)
1070		{
1071			uint32_t decomp[18]; /* 1 char decomps to a maximum of 18. */
1072			int i, n = ucdn_compat_decompose((uint32_t)c, decomp);
1073			if (n > 0)
1074			{
1075				len = 0;
1076				for (i = 0; i < n; i++)
1077				{
1078					size_t char_len = transform_char(ctx, output, index, decomp[i], pos, transform, cache);
1079					if (index)
1080						index += char_len;
1081					if (output)
1082						output += char_len;
1083					len += char_len;
1084				}
1085				return len;
1086			}
1087			transform &= ~FZ_TEXT_TRANSFORM_COMPATIBILITY_DECOMPOSE;
1088			/* Otherwise, it doesn't decompose to anything, so just fall
1089			 * through and process it as is.
1090			 */
1091		}
1092	
1093		if (transform & FZ_TEXT_TRANSFORM_STRIP_MARKING_NONSPACING)
1094		{
1095			if (ucdn_get_general_category(c) == UCDN_GENERAL_CATEGORY_MN)
1096				return 0;
1097		}
1098	
1099		if (transform & FZ_TEXT_TRANSFORM_FULLWIDTH_ASCII)
1100		{
1101			// Map full-width ASCII forms to ASCII:
1102			// U+FF01 .. U+FF5E => U+0021 .. U+007E
1103			if (c >= 0xFF01 && c <= 0xFF5E)
1104				c = c - 0xFF01 + 0x21;
1105		}
1106	
1107		if (transform & FZ_TEXT_TRANSFORM_NORMALIZE_HYPHENS)
1108			if (fz_is_unicode_hyphen(c))
1109				c = '-';
1110	
1111		if (transform & FZ_TEXT_TRANSFORM_UPPERCASE)
1112			c = fz_toupper(c);
1113	
1114		if (c == '\n' && (transform & (FZ_TEXT_TRANSFORM_KEEP_LINES | FZ_TEXT_TRANSFORM_KEEP_PARAGRAPHS)))
1115		{
1116			/* Don't strip \n if we might need it. */
1117		}
1118		else
1119			c = canon(c);
1120	
1121		/* Squash runs of spaces. */
1122		if (c == ' ' && cache->len > 0 && cache->cache[cache->len-1] == ' ')
1123			return 0;
1124	
1125		/* We keep a cache to allow for composition, and to remove runs of
1126		 * spaces.
1127		 */
1128		ccc = 0;
1129		if (transform & (FZ_TEXT_TRANSFORM_DECOMPOSE | FZ_TEXT_TRANSFORM_COMPATIBILITY_DECOMPOSE | FZ_TEXT_TRANSFORM_COMPOSE))
1130			ccc = ucdn_get_combining_class(c);
1131		/* If the cache is empty, we always store the character. */
1132		if (cache->len == 0)
1133		{
1134			cache->cache[cache->len] = c;
1135			cache->pos[cache->len] = pos;
1136			cache->len++;
1137			return 0;
1138		}
1139		/* Alternatively, if we've got a combining character, then we want to store that in the cache. */
1140		if (ccc > 0)
1141		{
1142			if (cache->len == nelem(cache->cache))
1143			{
1144				/* Cache is full. Just drop this character. This should never happen. */
1145				fz_warn(ctx, "Overfull unicode composition cache - character dropped");
1146				return 0;
1147			}
1148			cache->cache[cache->len] = c;
1149			cache->pos[cache->len] = pos;
1150			cache->len++;
1151			return 0;
1152		}
1153		/* So we've got a new base character. */
1154	
1155		/* Do we have a cache to flush? */
1156		len = flush_transform_cache(ctx, output, index, transform, cache);
1157		cache->len = 1;
1158		cache->cache[0] = c;
1159		cache->pos[0] = pos;
1160		return len;
1161	}
1162	
1163	static size_t
1164	do_transform(fz_context *ctx, fz_text_transform transform, char *output, size_t *index, const char *input)
1165	{
1166		size_t byte_len = 1; /* Allow for terminator */
1167		transform_cache cache;
1168		size_t pos = 0;
1169		size_t len;
1170		int c;
1171	
1172		cache.len = 0;
1173		while (1)
1174		{
1175			int inlen = fz_chartorune(&c, &input[pos]);
1176	
1177			if (c == 0)
1178				break;
1179	
1180			len = transform_char(ctx, output, index, c, pos, transform, &cache);
1181			if (index)
1182				index += len;
1183			if (output)
1184				output += len;
1185			byte_len += len;
1186			pos += inlen;
1187		}
1188	
1189		/* Flush the cache */
1190		len = flush_transform_cache(ctx, output, index, transform, &cache);
1191		if (index)
1192		{
1193			index += len;
1194			*index = pos;
1195		}
1196		if (output)
1197		{
1198			output += len;
1199			*output = 0;
1200		}
1201		byte_len += len;
1202	
1203		return byte_len;
1204	}
