1206	static char *
1207	transform_text_with_index(fz_context *ctx, fz_text_transform transform, const char *input, size_t **indexp)
1208	{
1209		char *output;
1210		size_t len = do_transform(ctx, transform, NULL, NULL, input);
1211	
1212		output = fz_malloc(ctx, len);
1213		fz_try(ctx)
1214		{
1215			*indexp = fz_malloc_array(ctx, len+1, size_t);
1216		}
1217		fz_catch(ctx)
1218		{
1219			fz_free(ctx, output);
1220			fz_rethrow(ctx);
1221		}
1222	
1223		(void)do_transform(ctx, transform, output, *indexp, input);
1224	
1225		return output;
1226	}
