1228	static char *
1229	transform_text_without_index(fz_context *ctx, fz_text_transform transform, const char *input)
1230	{
1231		char *output;
1232		size_t len = do_transform(ctx, transform, NULL, NULL, input);
1233		output = fz_malloc(ctx, len);
1234		(void)do_transform(ctx, transform, output, NULL, input);
1235		return output;
1236	}
