1301	static fz_text_transform
1302	init_transform_and_finder(fz_search_options options, const fz_match_finder **finder)
1303	{
1304		fz_text_transform trans = FZ_TEXT_TRANSFORM_NONE;
1305	
1306		if (options & FZ_SEARCH_KEEP_LINES)
1307			trans |= FZ_TEXT_TRANSFORM_KEEP_LINES;
1308		if (options & FZ_SEARCH_KEEP_PARAGRAPHS)
1309			trans |= FZ_TEXT_TRANSFORM_KEEP_PARAGRAPHS;
1310		if (options & FZ_SEARCH_KEEP_HYPHENS)
1311			trans |= FZ_TEXT_TRANSFORM_KEEP_HYPHENS;
1312	
1313		if (options & FZ_SEARCH_REGEXP)
1314		{
1315			if (options & FZ_SEARCH_IGNORE_CASE)
1316			{
1317				*finder = &regexp_finder_insensitive;
1318				options &= ~FZ_SEARCH_IGNORE_CASE;
1319			}
1320			else
1321				*finder = &regexp_finder;
1322		}
1323		else
1324		{
1325			*finder = &simple_finder;
1326		}
1327	
1328		switch (options & (FZ_SEARCH_IGNORE_CASE | FZ_SEARCH_IGNORE_DIACRITICS))
1329		{
1330		default:
1331		case FZ_SEARCH_EXACT:
1332			trans |= FZ_TEXT_TRANSFORM__NORMAL;
1333			break;
1334		case FZ_SEARCH_IGNORE_CASE:
1335			trans |= FZ_TEXT_TRANSFORM__IGNORE_CASE;
1336			break;
1337		case FZ_SEARCH_IGNORE_DIACRITICS:
1338			trans |= FZ_TEXT_TRANSFORM__IGNORE_DIACRITICS;
1339			break;
1340		case FZ_SEARCH_IGNORE_CASE | FZ_SEARCH_IGNORE_DIACRITICS:
1341			trans |= FZ_TEXT_TRANSFORM__IGNORE_CASE_DIACRITICS;
1342			break;
1343		}
1344	
1345		return trans;
1346	}
1347	
1348	fz_search *fz_new_search(fz_context *ctx, const char *needle, fz_search_options options)
1349	{
1350		fz_search *search = fz_malloc_struct(ctx, fz_search);
1351	
1352		search->hfuzz = 0.5f; /* merge large gaps */
1353		search->vfuzz = 0.1f;
1354	
1355		/* for the initial page feed before we start requesting pages */
1356		search->req_seq = 0;
1357		search->req_target = NULL;
1358	
1359		if (needle == NULL)
1360			fz_throw(ctx, FZ_ERROR_ARGUMENT, "Can't search for a non-existent needle");
1361	
1362		search->transform = init_transform_and_finder(options, &search->finder);
1363	
1364		/* Make sure we have a copy of the needle. */
1365		search->needle = fz_strdup(ctx, needle);
1366	
1367		/* Spin that needle into gold (to match the haystack) */
1368		if (search->transform == FZ_TEXT_TRANSFORM_NONE)
1369			search->spun_needle = search->needle;
1370		else
1371			search->spun_needle = transform_text_without_index(ctx, search->transform, search->needle);
1372	
1373		/* Compile the needle if required. */
1374		if (search->finder->init)
1375			search->finder->init(ctx, &search->compiled_needle, search->spun_needle);
1376	
1377		return search;
1378	}
