1380	static void
1381	drop_needle(fz_context *ctx, fz_search *search)
1382	{
1383		if (search->compiled_needle && search->finder->fin)
1384			search->finder->fin(ctx, &search->compiled_needle);
1385		search->compiled_needle = NULL;
1386		if (search->spun_needle != search->needle)
1387			fz_free(ctx, search->spun_needle);
1388		search->spun_needle = NULL;
1389		fz_free(ctx, search->needle);
1390		search->needle = NULL;
1391	}
