1393	static void
1394	drop_haystack(fz_context *ctx, search_page *page)
1395	{
1396		fz_free(ctx, page->map);
1397		fz_free(ctx, page->haystack);
1398		if (page->haystack != page->spun_haystack)
1399			fz_free(ctx, page->spun_haystack);
1400		fz_free(ctx, page->index);
1401	
1402		page->map = NULL;
1403		page->haystack = NULL;
1404		page->spun_haystack = NULL;
1405		page->index = NULL;
1406	
1407		page->length = 0;
1408		page->utf_length = 0;
1409		page->spun_length = 0;
1410	}
