1412	static void
1413	drop_combined(fz_context *ctx, fz_search *search)
1414	{
1415		fz_free(ctx, search->combined_spun_haystack);
1416		search->combined_spun_haystack = NULL;
1417		search->combined_spun_split_1 = 0;
1418		search->combined_spun_split_2 = 0;
1419		search->combined_spun_length = 0;
1420	}
