1423	zero_page(fz_context *ctx, search_page *page)
1424	{
1425		page->page = NULL;
1426		page->map = NULL;
1427		page->haystack = NULL;
1428		page->length = 0;
1429		page->utf_length = 0;
1430		page->spun_haystack = NULL;
