1453	static void
1454	advance_page(fz_context *ctx, fz_search *search)
1455	{
1456		drop_combined(ctx, search);
1457		move_page(ctx, search, &search->page[0], &search->page[1]);
1458		move_page(ctx, search, &search->page[1], &search->page[2]);
