1469	static void
1470	get_haystack(fz_context *ctx, search_page *ss, fz_stext_page *page, fz_text_transform transform)
1471	{
1472		fz_buffer *buffer;
1473		fz_text_flatten flatten = FZ_TEXT_FLATTEN_ALL;
1474	
1475		if (transform & FZ_TEXT_TRANSFORM_KEEP_LINES)
1476			flatten |= FZ_TEXT_FLATTEN_KEEP_LINES;
1477		if (transform & FZ_TEXT_TRANSFORM_KEEP_PARAGRAPHS)
1478			flatten |= FZ_TEXT_FLATTEN_KEEP_PARAGRAPHS;
1479		if (transform & FZ_TEXT_TRANSFORM_KEEP_HYPHENS)
1480			flatten |= FZ_TEXT_FLATTEN_KEEP_HYPHENS;
1481	
1482		buffer = fz_new_buffer_from_flattened_stext_page(ctx, page, flatten, &ss->map);
1483		fz_try(ctx)
1484		{
1485			fz_terminate_buffer(ctx, buffer);
1486			(void)fz_buffer_extract(ctx, buffer, (unsigned char **)&ss->haystack);
1487		}
1488		fz_always(ctx)
1489		{
1490			fz_drop_buffer(ctx, buffer);
1491		}
1492		fz_catch(ctx)
1493		{
1494			fz_free(ctx, ss->map);
1495			ss->map = NULL;
1496			fz_rethrow(ctx);
1497		}
1498	}
