1500	static int
1501	ensure_haystack_for_page(fz_context *ctx, fz_search *search, search_page *page)
1502	{
1503		char *s;
1504		int c;
1505	
1506		if (page->end_of_doc)
1507		{
1508			return 0;
1509		}
1510	
1511		if (page->haystack == NULL)
1512		{
1513			get_haystack(ctx, page, page->page, search->transform);
1514			page->length = strlen(page->haystack);
1515			page->utf_length = fz_utflen(page->haystack);
1516		}
1517	
1518		/* skip initial whitespace looking for the first non-whitespace character */
1519		s = page->haystack;
1520		while (*s)
1521		{
1522			s += fz_chartorune(&c, s);
1523			if (!fz_is_unicode_whitespace(c))
1524				return 0;
1525		}
1526	
1527		/* no non-whitespace character found! */
1528		drop_haystack(ctx, page);
1529		return 1;
1530	}
1531	
1532	static void
1533	ensure_spun_haystack_for_page(fz_context *ctx, fz_search *search, search_page *page)
1534	{
1535		if (page->spun_haystack != NULL)
1536			return;
1537	
1538		assert(page->index == NULL);
1539	
1540		if (page->haystack == NULL)
1541		{
1542			page->spun_haystack = NULL;
1543			page->spun_length = 0;
1544			page->index = NULL;
1545		}
1546		else
1547		{
1548			if (search->transform == FZ_TEXT_TRANSFORM_NONE)
1549			{
1550				page->spun_haystack = page->haystack;
1551				page->spun_length = page->length;
1552				page->index = NULL;
1553			}
1554			else
1555			{
1556				page->spun_haystack = transform_text_with_index(ctx, search->transform, page->haystack, &page->index);
1557				page->spun_length = strlen(page->spun_haystack);
1558			}
1559		}
1560	
1561	}
1562	
1563	static void
1564	ensure_combined_spun_haystack(fz_context *ctx, fz_search *search)
1565	{
1566		search_page *p1 = &search->page[0];
1567		search_page *p2 = &search->page[1];
1568		search_page *p3 = &search->page[2];
1569	
1570		if (search->combined_spun_haystack != NULL)
1571			return;
1572	
1573		search->combined_spun_split_1 = p1->spun_length;
1574		search->combined_spun_split_2 = p1->spun_length + p2->spun_length;
1575		search->combined_spun_length = p1->spun_length + p2->spun_length + p3->spun_length;
1576	
1577		search->combined_spun_haystack = fz_malloc(ctx, search->combined_spun_length + 1);
1578		if (p1->spun_length)
1579			memcpy(search->combined_spun_haystack, p1->spun_haystack, p1->spun_length);
1580		if (p2->spun_length)
1581			memcpy(search->combined_spun_haystack + p1->spun_length, p2->spun_haystack, p2->spun_length);
1582		if (p3->spun_length)
1583			memcpy(search->combined_spun_haystack + p1->spun_length + p2->spun_length, p3->spun_haystack, p3->spun_length);
1584		search->combined_spun_haystack[search->combined_spun_length] = 0;
1585	}
1586	
1587	static fz_stext_position
1588	lookup_stext_position(fz_context *ctx, fz_search *search, const char *spun)
1589	{
1590		search_page *page1 = &search->page[0];
1591		search_page *page2 = &search->page[1];
1592		search_page *page3 = &search->page[2];
1593		search_page *page;
1594		size_t spun_ix;
1595		size_t page_spun_ix;
1596		size_t page_unspun_ix;
1597		size_t utf_ix;
1598	
1599		assert(spun >= search->combined_spun_haystack && spun < search->combined_spun_haystack + search->combined_spun_length);
1600	
1601		spun_ix = spun - search->combined_spun_haystack;
1602		assert(spun_ix >= 0 && spun_ix < search->combined_spun_length);
1603	
1604		if (spun_ix < search->combined_spun_split_1)
1605		{
1606			page = page1;
1607			page_spun_ix = spun_ix;
1608		}
1609		else if (spun_ix < search->combined_spun_split_2)
1610		{
1611			page = page2;
1612			page_spun_ix = spun_ix - search->combined_spun_split_1;
1613		}
1614		else
1615		{
1616			page = page3;
1617			page_spun_ix = spun_ix - search->combined_spun_split_2;
1618		}
1619		assert(page_spun_ix >= 0 && page_spun_ix < page->spun_length);
1620	
1621		page_unspun_ix = page->index ? page->index[page_spun_ix] : page_spun_ix;
1622		assert(page_unspun_ix >= 0 && page_unspun_ix < page->length);
1623	
1624		utf_ix = fz_runeidx(page->haystack, page->haystack + page_unspun_ix);
1625	
1626		return page->map[utf_ix];
1627	}
1628	
1629	static fz_stext_position
1630	lookup_stext_position_end(fz_context *ctx, fz_search *search, const char *spun)
1631	{
1632		fz_stext_position pos = lookup_stext_position(ctx, search, spun);
1633		while (pos.ch && pos.ch->next && ucdn_get_general_category(pos.ch->next->c) == UCDN_GENERAL_CATEGORY_MN)
1634			pos.ch = pos.ch->next;
1635		return pos;
1636	}
1637	
1638	static int
1639	lookup_stext_seq(fz_search *search, fz_stext_position *pos)
1640	{
1641		if (pos->page == search->page[0].page) return search->page[0].seq;
1642		if (pos->page == search->page[1].page) return search->page[1].seq;
1643		if (pos->page == search->page[2].page) return search->page[2].seq;
1644		return -1;
1645	}
1646	
1647	static void add_quad(fz_context *ctx, fz_search *search, fz_stext_position *pos, int seq)
1648	{
1649		fz_stext_line *line = pos->line;
1650		fz_stext_char *ch = pos->ch;
1651		float vfuzz = ch->size * search->vfuzz;
1652		float hfuzz = ch->size * search->hfuzz;
1653	
1654		/* Can we merge this quad into the last one we already have? */
1655		if (search->match.num_quads > 0)
1656		{
1657			fz_search_quad *end = &search->match.quads[search->match.num_quads-1];
1658			if (end->seq == seq
1659				&& hdist(&line->dir, &end->quad.lr, &ch->quad.ll) < hfuzz
1660				&& vdist(&line->dir, &end->quad.lr, &ch->quad.ll) < vfuzz
1661				&& hdist(&line->dir, &end->quad.ur, &ch->quad.ul) < hfuzz
1662				&& vdist(&line->dir, &end->quad.ur, &ch->quad.ul) < vfuzz)
1663			{
1664				/* Yes */
1665				end->quad.ur = ch->quad.ur;
1666				end->quad.lr = ch->quad.lr;
1667				return;
1668			}
1669		}
1670	
1671		if (search->match.num_quads == search->match_quads_max)
1672		{
1673			int newmax = search->match_quads_max * 2;
1674			if (newmax == 0)
1675				newmax = 32;
1676			search->match.quads = fz_realloc(ctx, search->match.quads, sizeof(search->match.quads[0]) * newmax);
1677			search->match_quads_max = newmax;
1678		}
1679		search->match.quads[search->match.num_quads].seq = seq;
1680		search->match.quads[search->match.num_quads++].quad = ch->quad;
1681	}
1682	
1683	static fz_search_result result_complete = { FZ_SEARCH_COMPLETE };
1684	
1685	static fz_search_result
1686	request_page(fz_context *ctx, fz_search *search, int seq, search_page *page)
1687	{
1688		fz_search_result result;
1689		search->req_seq = seq;
1690		search->req_target = page;
1691		result.reason = FZ_SEARCH_MORE_INPUT;
1692		result.u.seq_needed = seq;
1693		return result;
1694	}
1695	
1696	static fz_search_result
1697	fz_search_imp(fz_context *ctx, fz_search *search, int direction)
1698	{
1699		fz_search_result result;
1700		const char *spun_begin, *spun_end, *p;
1701		int seq;
1702	
1703		if (search == NULL)
1704			fz_throw(ctx, FZ_ERROR_ARGUMENT, "Can't search in a non-existent search");
1705		if (direction != -1 && direction != 1)
1706			fz_throw(ctx, FZ_ERROR_ARGUMENT, "Invalid search direction (must be 1 or -1)");
1707		if (direction < 0 && search->finder->find_rev == NULL)
1708			fz_throw(ctx, FZ_ERROR_ARGUMENT, "Can't search backwards with this finder");
1709	
1710		if (search->needle == NULL || *search->needle == 0)
1711			return result_complete;
1712	
1713		/* On entry, we assume that current_spun_pos point a position within
1714		 * the combined spun haystack if it exists. We may have ditched the
1715		 * combined spun haystack, but the position within that buffer, when
1716		 * reformed, should be valid.
1717		 */
1718		assert(search->combined_spun_haystack == NULL || search->current_spun_pos <= search->combined_spun_length);
1719	
1720		/* Was the last search in a different direction? If so, we need to discard the duplicate result that we'll find. */
1721		if (search->last_direction && search->last_direction != direction)
1722			search->discard_next_match = 1;
1723		search->last_direction = direction;
1724	
1725	restart:
1726	
1727		/* We need to have a current page. */
1728		if (search->page[CURRENT_PAGE].page == NULL)
1729		{
1730			if (search->page[CURRENT_PAGE].end_of_doc)
1731				return result_complete;
1732			return request_page(ctx, search, 0, &search->page[CURRENT_PAGE]); /* Any seq will do! */
1733		}
1734	
1735		/* If the current page is empty (and it's not the final page) */
1736		if (search->page[CURRENT_PAGE].haystack == NULL && !search->page[CURRENT_PAGE].end_of_doc)
1737		{
1738			/* Ditch current page, then ask for the next page to take its place. */
1739			seq = search->page[CURRENT_PAGE].seq + direction;
1740			drop_page(ctx, &search->page[CURRENT_PAGE]);
1741			return request_page(ctx, search, seq, &search->page[CURRENT_PAGE]);
1742		}
1743	
1744		/* We need to either have the next page, or to know there is no next page. */
1745		if (search->page[CURRENT_PAGE+direction].page == NULL && !search->page[CURRENT_PAGE+direction].end_of_doc)
1746		{
1747			return request_page(ctx, search, search->page[CURRENT_PAGE].seq + direction, &search->page[CURRENT_PAGE+direction]);
1748		}
1749	
1750		/* The next page was empty (and not the last page) */
1751		if (!search->page[CURRENT_PAGE+direction].end_of_doc && search->page[CURRENT_PAGE+direction].haystack == NULL)
1752		{
1753			/* Ditch the next page, then ask for the next-next page to take its place. */
1754			seq = search->page[CURRENT_PAGE+direction].seq + direction;
1755			drop_page(ctx, &search->page[CURRENT_PAGE+direction]);
1756			return request_page(ctx, search, seq, &search->page[CURRENT_PAGE+direction]);
1757		}
1758	
1759		/* Then spin all the hay (for all the loaded pages) into gold. */
1760		ensure_combined_spun_haystack(ctx, search);
1761	
1762		/* Where are we searching from? */
1763		if (!search->is_current_spun_pos_valid)
1764		{
1765			/* Search from the first or last char on the current page depending on direction. */
1766			search->is_current_spun_pos_valid = 1;
1767			search->current_spun_pos = (direction > 0) ? search->combined_spun_split_1 : search->combined_spun_split_2;
1768		}
1769		else
1770		{
1771			/* Forwards search from the char before where we matched before. */
1772			/* Backwards search from the char after the end of the previous match. */
1773		}
1774	
1775		/* If we're searching forwards and the current position is on the
1776		 * next page, we need to shift the window so that we can find
1777		 * matches that straddle the page boundary of the next and
1778		 * next-next page (current and next page after shifting).
1779		 */
1780		if (direction > 0 && search->current_spun_pos >= search->combined_spun_split_2)
1781		{
1782			/* Note: We adjust the current position by subtracting the previous page's length,
1783			 * so that it remains at the same relative position after shifting the window.
1784			 */
1785			search->current_spun_pos -= search->combined_spun_split_1;
1786			advance_page(ctx, search);
1787			goto restart;
1788		}
1789	
1790		/* If we're searching backwards and the current position is on the
1791		 * previous page, we need to shift the window so that we can find
1792		 * matches that straddle the page boundary of the previous-previous and
1793		 * previous page (previous and current page after shifting).
1794		 */
1795		if (direction < 0 && search->current_spun_pos < search->combined_spun_split_1)
1796		{
1797			/* Note: the current position will be updated when fz_feed_search receives the page. */
1798			retreat_page(ctx, search);
1799			goto restart;
1800		}
1801	
1802		/* Assert that our offsets make sense. */
1803		assert(search->combined_spun_split_1 <= search->combined_spun_length);
1804		assert(search->combined_spun_split_2 <= search->combined_spun_length);
1805		if (direction > 0) assert(search->current_spun_pos <= search->combined_spun_split_2);
1806		if (direction < 0) assert(search->current_spun_pos >= search->combined_spun_split_1);
1807	
1808		/* Search within the combined_spun_haystack onwards from current_spun_pos. */
1809		spun_begin = (direction > 0 ? search->finder->find : search->finder->find_rev)(ctx,
1810			&search->compiled_needle,
1811			search->combined_spun_haystack,
1812			search->combined_spun_haystack + search->current_spun_pos,
1813			search->spun_needle,
1814			&spun_end
1815		);
1816	
1817		if (spun_begin && spun_end)
1818		{
1819			/* We found a match! spun_begin points to first char of match, spun_end points to first char after match */
1820	
1821			if (direction > 0)
1822			{
1823				/* Next search should start after last character of this match. */
1824				search->current_spun_pos = spun_end - search->combined_spun_haystack;
1825			}
1826			else
1827			{
1828				/* Next search should start at first character of this match. */
1829				search->current_spun_pos = spun_begin - search->combined_spun_haystack;
1830			}
1831	
1832			/* We need to discard the match, because we changed direction. */
1833			if (search->discard_next_match)
1834			{
1835				search->discard_next_match = 0;
1836				goto restart;
1837			}
1838	
1839			/* spun_begin and spun_end must now point to first and last characters of match */
1840	
1841			spun_end = retreat_one_utf8(search->combined_spun_haystack, spun_end);
1842	
1843			/* Skip over spun characters that have no matching stext character (inserted line ends, removed spaces, etc) */
1844			while (spun_begin < spun_end && lookup_stext_position(ctx, search, spun_begin).ch == NULL)
1845				spun_begin = advance_one_utf8(search->combined_spun_haystack, spun_begin);
1846			while (spun_end > spun_begin && lookup_stext_position(ctx, search, spun_end).ch == NULL)
1847				spun_end = retreat_one_utf8(search->combined_spun_haystack, spun_end);
1848	
1849			/* Remember the location of the match. */
1850			search->match.begin = lookup_stext_position(ctx, search, spun_begin);
1851			search->match.end = lookup_stext_position_end(ctx, search, spun_end);
1852	
1853			/* Skip matches that consist of synthetic characters */
1854			// TODO: We could create a fake fz_stext_char to return the synthetic space here.
1855			// However, there's not much utility to be had from being able
1856			// to search for single space characters that stand in for line
1857			// and paragraph breaks.
1858			if (!search->match.begin.ch || !search->match.end.ch)
1859				goto restart;
1860	
1861			search->match.begin_seq = lookup_stext_seq(search, &search->match.begin);
1862			search->match.end_seq = lookup_stext_seq(search, &search->match.end);
1863	
1864			/* Gather the quads for the result hit. */
1865			search->match.num_quads = 0;
1866			for (p = spun_begin; p <= spun_end; p = advance_one_utf8(search->combined_spun_haystack, p))
1867			{
1868				fz_stext_position pos = lookup_stext_position(ctx, search, p);
1869				if (pos.ch != NULL)
1870				{
1871					size_t spun_ix = p - search->combined_spun_haystack;
1872					if (spun_ix < search->combined_spun_split_1)
1873						seq = search->page[PREVIOUS_PAGE].seq;
1874					else if (spun_ix < search->combined_spun_split_2)
1875						seq = search->page[CURRENT_PAGE].seq;
1876					else
1877						seq = search->page[NEXT_PAGE].seq;
1878					add_quad(ctx, search, &pos, seq);
1879				}
1880			}
1881	
1882			result.reason = FZ_SEARCH_MATCH;
1883			result.u.match = &search->match;
1884			return result;
1885		}
1886	
1887		/* We failed to match. */
1888	
1889		/* Start any future searches from the next page (no current position) */
1890		search->is_current_spun_pos_valid = 0;
1891	
1892		/* End of doc? We're done! */
1893		if (search->page[CURRENT_PAGE+direction].end_of_doc)
1894			return result_complete;
1895	
1896		/*
1897		 * There may still be a match straddling the next page and the page after that.
1898		 * We slide the window one page in the search direction, and start searching anew
1899		 * on the next page.
1900		 */
1901		if (direction > 0)
1902			advance_page(ctx, search);
1903		else
1904			retreat_page(ctx, search);
1905	
1906		return request_page(ctx, search, search->page[CURRENT_PAGE].seq + direction, &search->page[CURRENT_PAGE+direction]);
1907	}
1908	
1909	fz_search_result fz_search_forwards(fz_context *ctx, fz_search *search)
1910	{
1911		return fz_search_imp(ctx, search, 1);
1912	}
1913	
1914	fz_search_result fz_search_backwards(fz_context *ctx, fz_search *search)
1915	{
1916		return fz_search_imp(ctx, search, -1);
1917	}
1918	
1919	void fz_feed_search(fz_context *ctx, fz_search *search, fz_stext_page *page, int seq)
1920	{
1921		search_page *pg;
1922	
1923		if (search == NULL)
1924			fz_throw(ctx, FZ_ERROR_ARGUMENT, "Can't feed a non-existent search");
1925	
1926		if (search->req_target == NULL)
1927		{
1928			/* we are force-fed the first page to start searching on */
1929			search->req_target = &search->page[CURRENT_PAGE];
1930		}
1931		else
1932		{
1933			/* we have requested a page! make sure we get the one we asked for. */
1934			if (search->req_seq != seq)
1935				fz_throw(ctx, FZ_ERROR_ARGUMENT, "Not the requested page (requested %d, got %d)", search->req_seq, seq);
1936		}
1937	
1938		pg = search->req_target;
1939	
1940		drop_page(ctx, pg);
1941	
1942		pg->page = page;
1943		pg->seq = seq;
1944		pg->end_of_doc = (page == NULL);
1945	
1946		/* Prepare a haystack for the page. */
1947		if (ensure_haystack_for_page(ctx, search, pg))
1948		{
1949			/* The page is empty! */
1950			return;
1951		}
1952	
1953		/* We also need the page to have a spun haystack. */
1954		ensure_spun_haystack_for_page(ctx, search, pg);
1955	
1956		/* Update current spun pos now that we know the length of the previous page. */
1957		if (search->is_current_spun_pos_valid && search->req_target == &search->page[PREVIOUS_PAGE])
1958		{
1959			search->current_spun_pos += search->page[PREVIOUS_PAGE].spun_length;
1960		}
1961	
1962		/* We have a new page, so the combined haystack content is invalid */
1963		drop_combined(ctx, search);
1964	}
1965	
1966	void fz_drop_search(fz_context *ctx, fz_search *search)
1967	{
1968		if (search == NULL)
1969			return;
1970	
1971		drop_page(ctx, &search->page[CURRENT_PAGE]);
1972		drop_page(ctx, &search->page[PREVIOUS_PAGE]);
1973		drop_page(ctx, &search->page[NEXT_PAGE]);
1974		drop_combined(ctx, search);
1975		drop_needle(ctx, search);
1976		fz_free(ctx, search->match.quads);
1977		fz_free(ctx, search);
1978	}
1979	
1980	/*
1981	 * Non-iterative search functions (using iterative API internally).
1982	 */
1983	
1984	int
1985	fz_match_stext_page_cb(fz_context *ctx, fz_stext_page *page, const char *needle, fz_match_callback_fn *cb, void *opaque, fz_search_options options)
1986	{
1987		fz_search *search = fz_new_search(ctx, needle, options);
1988		fz_search_result res;
1989		fz_quad *quads = NULL;
1990		int quad_max = 0;
1991		int hits = 0;
1992	
1993		fz_var(search);
1994		fz_var(quads);
1995	
1996		fz_try(ctx)
1997		{
1998			fz_feed_search(ctx, search, fz_keep_stext_page(ctx, page), 0);
1999	
2000			do
2001			{
2002				res = fz_search_forwards(ctx, search);
2003				if (res.reason == FZ_SEARCH_MORE_INPUT)
2004				{
2005					fz_feed_search(ctx, search, NULL, res.u.seq_needed);
2006				}
2007				else if (res.reason == FZ_SEARCH_MATCH)
2008				{
2009					fz_search_match *details = res.u.match;
2010					if (cb != NULL && details->num_quads > 0)
2011					{
2012						int i;
2013						if (details->num_quads > quad_max)
2014						{
2015							quads = fz_realloc(ctx, quads, sizeof(*quads) * details->num_quads);
2016							quad_max = details->num_quads;
2017						}
2018						for (i = 0; i < details->num_quads; i++)
2019							quads[i] = details->quads[i].quad;
2020						cb(ctx, opaque, details->num_quads, quads, 0, 0);
2021					}
2022					hits++;
2023				}
2024			}
2025			while (res.reason != FZ_SEARCH_COMPLETE);
2026		}
2027		fz_always(ctx)
2028		{
2029			fz_free(ctx, quads);
2030			fz_drop_search(ctx, search);
2031		}
2032		fz_catch(ctx)
2033			fz_rethrow(ctx);
2034	
2035		return hits;
2036	}
2037	
2038	typedef struct
2039	{
2040		fz_search_callback_fn *cb;
2041		void *opaque;
2042	} match2search_data;
2043	
2044	static int match2search(fz_context *ctx, void *opaque, int num_quads, fz_quad *hit_bbox, int chapter, int page)
2045	{
2046		match2search_data *md = (match2search_data *)opaque;
2047	
2048		return md->cb(ctx, md->opaque, num_quads, hit_bbox);
2049	}
2050	
2051	int
2052	fz_search_stext_page_cb(fz_context *ctx, fz_stext_page *page, const char *needle, fz_search_callback_fn *cb, void *opaque)
2053	{
2054		match2search_data md = { cb, opaque };
2055	
2056		return fz_match_stext_page_cb(ctx, page, needle, match2search, &md, FZ_SEARCH_IGNORE_CASE);
2057	}
2058	
2059	typedef struct
2060	{
2061		int *hit_mark;
2062		fz_quad *quads;
2063		int max_quads;
2064		int fill;
2065		int hit;
2066	} oldsearch_data;
2067	
2068	static int
2069	oldsearch_cb(fz_context *ctx, void *opaque, int num_quads, fz_quad *quads)
2070	{
2071		oldsearch_data *data = (oldsearch_data *)opaque;
2072		int i;
2073		int hit = data->hit++;
2074	
2075		for (i = 0; i < num_quads; i++)
2076		{
2077			if (data->fill == data->max_quads)
2078				break;
2079			if (data->hit_mark)
2080				data->hit_mark[data->fill] = hit;
2081			data->quads[data->fill] = quads[i];
2082			data->fill++;
2083		}
2084	
2085		/* We never return 1 here, even if we fill up the buffer, as we
2086		 * want the old API to get the correct total number of quads.
2087		 */
2088		return 0;
2089	}
2090	
2091	int
2092	fz_search_stext_page(fz_context *ctx, fz_stext_page *page, const char *needle, int *hit_mark, fz_quad *quads, int max_quads)
2093	{
2094		oldsearch_data data;
2095		match2search_data md = { oldsearch_cb, &data };
2096	
2097		data.hit_mark = hit_mark;
2098		data.quads = quads;
2099		data.max_quads = max_quads;
2100		data.fill = 0;
2101		data.hit = 0;
2102		(void)fz_match_stext_page_cb(ctx, page, needle, match2search, &md, FZ_SEARCH_IGNORE_CASE);
2103	
2104		return data.fill; /* Return the number of quads we have read */
2105	}
2106	
2107	int
2108	fz_match_stext_page(fz_context *ctx, fz_stext_page *page, const char *needle, int *hit_mark, fz_quad *quads, int max_quads, fz_search_options options)
2109	{
2110		oldsearch_data data;
2111		match2search_data md = { oldsearch_cb, &data };
2112	
2113		data.hit_mark = hit_mark;
2114		data.quads = quads;
2115		data.max_quads = max_quads;
2116		data.fill = 0;
2117		data.hit = 0;
2118	
2119		(void)fz_match_stext_page_cb(ctx, page, needle, match2search, &md, options);
2120	
2121		return data.fill; /* Return the number of quads we have read */
2122	}
